const ARROW_PADDING = 8;
const ARROW_WIDTH = 10;
export const tooltipAlignments = {
    top: (triggerRect, popupRect, parentRect, _, paddingY) => ({
        top: triggerRect.top - parentRect.top - popupRect.height - paddingY,
        left: triggerRect.left - parentRect.left - (popupRect.width - triggerRect.width) / 2
    }),
    "top-left": (triggerRect, popupRect, parentRect, _2, paddingY) => ({
        top: triggerRect.top - parentRect.top - popupRect.height - paddingY,
        left: triggerRect.left - parentRect.left + (triggerRect.right - triggerRect.left) / 2 - (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    "top-right": (triggerRect, popupRect, parentRect, _2, paddingY) => ({
        top: triggerRect.top - parentRect.top - popupRect.height - paddingY,
        right: parentRect.right - triggerRect.right + (triggerRect.right - triggerRect.left) / 2 - (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    bottom: (triggerRect, popupRect, parentRect, _, paddingY) => ({
        top: triggerRect.top - parentRect.top + triggerRect.height + paddingY,
        left: triggerRect.left - parentRect.left - (popupRect.width - triggerRect.width) / 2
    }),
    "bottom-left": (triggerRect, _1, parentRect, _2, paddingY) => ({
        top: triggerRect.top - parentRect.top + triggerRect.height + paddingY,
        left: triggerRect.left - parentRect.left + (triggerRect.right - triggerRect.left) / 2 - (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    "bottom-right": (triggerRect, _1, parentRect, _2, paddingY) => ({
        top: triggerRect.top - parentRect.top + triggerRect.height + paddingY,
        right: parentRect.right - triggerRect.right + (triggerRect.right - triggerRect.left) / 2 - (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    left: (triggerRect, popupRect, parentRect, paddingX, _) => ({
        right: parentRect.right - triggerRect.right + triggerRect.width + paddingX,
        top: triggerRect.top - parentRect.top - (popupRect.height - triggerRect.height) / 2
    }),
    "left-top": (triggerRect, _1, parentRect, paddingX, _2) => ({
        right: parentRect.right - triggerRect.right + triggerRect.width + paddingX,
        top: triggerRect.top - parentRect.top + triggerRect.height / 2 - (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    "left-bottom": (triggerRect, popupRect, parentRect, paddingX, _2) => ({
        right: parentRect.right - triggerRect.right + triggerRect.width + paddingX,
        top: triggerRect.top - parentRect.top + triggerRect.height / 2 - popupRect.height + (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    right: (triggerRect, popupRect, parentRect, paddingX, _) => ({
        left: triggerRect.left - parentRect.left + triggerRect.width + paddingX,
        top: triggerRect.top - parentRect.top - (popupRect.height - triggerRect.height) / 2
    }),
    "right-top": (triggerRect, _1, parentRect, paddingX, _2) => ({
        left: triggerRect.left - parentRect.left + triggerRect.width + paddingX,
        top: triggerRect.top - parentRect.top + (triggerRect.bottom - triggerRect.top) / 2 - (ARROW_PADDING + ARROW_WIDTH / 2)
    }),
    "right-bottom": (triggerRect, popupRect, parentRect, paddingX, _2) => ({
        left: triggerRect.left - parentRect.left + triggerRect.width + paddingX,
        top: triggerRect.top - parentRect.top + triggerRect.height / 2 - popupRect.height + (ARROW_PADDING + ARROW_WIDTH / 2)
    })
};
