import { hasErrorProps } from "../../commonHelpers/loading";
export const useDisabled = (props) => {
    const controller = props.controller;
    let disabled = props.disabled;
    if (hasErrorProps(props)) {
        if (controller) {
            controller.disabled = true;
        }
        else {
            disabled = true;
        }
        return {
            controller,
            disabled
        };
    }
    return {};
};
