export const normalizeVertically = (position, popupRect, parentHeight) => {
    if (parentHeight <= popupRect.height) {
        position.top = 0;
        position.bottom = 0;
        return;
    }
    if (position.top) {
        if (position.top < 0) {
            position.top = 0;
        }
        const overflowTop = position.top + popupRect.height - parentHeight;
        if (overflowTop <= 0) {
            return;
        }
        position.top = parentHeight - popupRect.height;
        return;
    }
    if (position.bottom) {
        if (position.bottom < 0) {
            position.bottom = 0;
        }
        const overflowBottom = position.bottom + popupRect.height - parentHeight;
        if (overflowBottom <= 0) {
            return;
        }
        position.bottom = parentHeight - popupRect.height;
        return;
    }
};
